+      "argv": ["ZMPOP", "1", "zmpop_a", "MIN"],
+      "expect": {
+        "kind": "array",
+        "value": [
+          { "kind": "bulk", "value": "zmpop_a" },
+          {
+            "kind": "array",
+            "value": [
+              { "kind": "bulk", "value": "one" },
+              { "kind": "bulk", "value": "1" }
+            ]
+          }
+        ]
+      }
+    },
+    {
+      "name": "zmpop_max_single",
+      "now_ms": 1000,
+      "argv": ["ZMPOP", "1", "zmpop_a", "MAX"],
+      "expect": {
+        "kind": "array",
+        "value": [
+          { "kind": "bulk", "value": "zmpop_a" },
+          {
+            "kind": "array",
+            "value": [
+              { "kind": "bulk", "value": "three" },
+              { "kind": "bulk", "value": "3" }
+            ]
+          }
+        ]
+      }
+    },
+    {
+      "name": "zmpop_verify_remaining",
