+    {
+      "name": "zmpop_min_count_2",
+      "now_ms": 1010,
+      "argv": ["ZMPOP", "1", "zmpop_b", "MIN", "COUNT", "2"],
+      "expect": {
+        "kind": "array",
+        "value": [
+          { "kind": "bulk", "value": "zmpop_b" },
+          {
+            "kind": "array",
+            "value": [
+              { "kind": "bulk", "value": "alpha" },
+              { "kind": "bulk", "value": "10" },
+              { "kind": "bulk", "value": "beta" },
+              { "kind": "bulk", "value": "20" }
